// =====================================================
// 1) قراءة البيانات القادمة من Evolution API
// =====================================================

const body = $json.body || {};
const data = body.data || {};
const msg = data.message || {};

// =====================================================
// 2) استخراج رقم الواتساب للمرسل
// =====================================================

const jid =
  data.key?.remoteJid ||
  data.key?.remoteJidAlt ||
  "";

// =====================================================
// 3) تجاهل المجموعات
// لا نعالج أي رسالة قادمة من جروب
// =====================================================

if (!jid || jid.includes("@g.us")) {
  return [];
}

// =====================================================
// 4) تنظيف رقم الهاتف
// تحويل:
// 9715xxxx@s.whatsapp.net
// إلى:
// 9715xxxx
// =====================================================

const phone = jid
  .replace("@s.whatsapp.net", "")
  .replace("@lid", "")
  .replace("@c.us", "")
  .trim();


// =====================================================
// 5) استخراج نص الرسالة
// يدعم:
// - الرسائل النصية
// - الأزرار
// - القوائم
// =====================================================

const text =
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.buttonsResponseMessage?.selectedButtonId ||
  msg.templateButtonReplyMessage?.selectedId ||
  msg.listResponseMessage?.singleSelectReply?.selectedRowId ||
  "";


// =====================================================
// 6) استخراج رقم البوت المستقبل
// =====================================================

const receiver = (body.sender || "")
  .replace("@s.whatsapp.net", "")
  .trim();


// =====================================================
// 7) استخراج Message ID
//
// هذا هو المفتاح الأساسي لتطبيق Idempotency
//
// كل رسالة واتساب لها ID فريد
// سنخزنه في قاعدة البيانات
//
// إذا وصل نفس الـ ID مرة ثانية:
// نتجاهل الرسالة
// =====================================================

const messageId =
  data.key?.id ||
  msg.key?.id ||
  body.key?.id ||
  "";


// =====================================================
// 8) وقت وصول الرسالة
//
// يساعد لاحقاً في:
// - التقارير
// - التتبع
// - اكتشاف التكرار
// =====================================================

const messageTime = new Date().toISOString();

// =====================================================
// 9) تحديد هل الرقم إماراتي
//
// true  => يبدأ بـ 971
// false => أي دولة أخرى
// =====================================================

const isUAE = phone.startsWith("971");

// =====================================================
// 10) إخراج البيانات لبقية الووركفلو
// =====================================================

return [
  {
    json: {

      // بيانات العميل
      phone,
      pushName: data.pushName || "",

      // الرسالة
      text,

      // رقم البوت
      receiver,

      // الدولة
      isUAE,

      // Idempotency
      message_id: messageId,
      message_time: messageTime

    }
  }
];

