const current = $('Code in JavaScript').first().json;
const ai = $('AI Agent').first().json;
const context = $('Build Agent Context').first().json;
const session = context.session || {};

// =====================================================
// Helpers
// =====================================================

function normalizeArabicNumerals(str) {
  const arabicIndic = '٠١٢٣٤٥٦٧٨٩';
  const easternArabic = '۰۱۲۳۴۵۶۷۸۹';

  return (str || '').replace(/[٠-٩۰-۹]/g, d => {
    let idx = arabicIndic.indexOf(d);
    if (idx > -1) return idx.toString();

    idx = easternArabic.indexOf(d);
    if (idx > -1) return idx.toString();

    return d;
  });
}

function normalizeText(str) {
  return (str || '')
    .toLowerCase()
    .replace(/[أإآ]/g, 'ا')
    .replace(/ى/g, 'ي')
    .replace(/ة/g, 'ه')
    .replace(/[ًٌٍَُِّْ]/g, '')
    .trim();
}

function parseCart(value) {
  try {
    if (!value) return [];
    if (Array.isArray(value)) return value;
    return JSON.parse(value);
  } catch {
    return [];
  }
}

function addOrUpdateCart(cart, item) {
  const index = cart.findIndex(i => i.id === item.id && i.weight === item.weight);

  if (index >= 0) {
    cart[index].quantity = String(Number(cart[index].quantity || 0) + Number(item.quantity || 1));
    cart[index].price = item.price;
  } else {
    cart.push(item);
  }

  return cart;
}

function removeFromCart(cart, id) {
  return cart.filter(i => i.id !== id);
}

// =====================================================
// Products / Prices
