function getPrice(id, weight) {
  return priceTable[id]?.[weight] || 0;
}

function mapProductFromName(name) {
  const n = normalizeText(name);

  if (n.includes('كركديه') || n.includes('كركدي')) {
    return productRules.find(r => r.id === 'hibiscus');
  }

  if (n.includes('زيت سمسم') || n.includes('سمسم')) {
    return productRules.find(r => r.id === 'sesame_oil');
  }

  if (n.includes('تعليقة بلس')) {
    return productRules.find(r => r.id === 'tea_bag_plus');
  }

  if (n.includes('تعليقة')) {
    return productRules.find(r => r.id === 'tea_bag');
  }

  if (n.includes('اصيل') || n.includes('أصيل')) {
    return productRules.find(r => r.id === 'tea_aseel');
  }

  if (n.includes('op1') || n.includes('سبيشل')) {
    return productRules.find(r => r.id === 'tea_op1');
  }

  if (n.includes('عراقي')) {
    return productRules.find(r => r.id === 'iraqi_tea');
  }

  if (n.includes('السوداء') || n.includes('سوداء')) {
    return productRules.find(r => r.id === 'black_coffee');
  }

  if (n.includes('البنية') || n.includes('بنية')) {
    return productRules.find(r => r.id === 'brown_coffee');
  }

  if (n.includes('الشقراء') || n.includes('شقرا') || n.includes('شقراء')) {
    return productRules.find(r => r.id === 'blonde_coffee');
  }

  for (const rule of productRules) {
    if (rule.keywords.some(k => n.includes(normalizeText(k)))) {
      return rule;
    }
  }

  return null;
}

function normalizeWeight(weightText, productId = '') {
  const t = normalizeText(weightText);

  if (productId === 'hibiscus') return '250g';
  if (productId === 'sesame_oil') return '500ml';

  if (['tea_bag', 'tea_bag_plus', 'tea_aseel', 'tea_op1', 'iraqi_tea'].includes(productId)) {
    return 'عبوة';
  }

  if (t.includes('250')) return '250g';
  if (t.includes('500') && t.includes('مل')) return '500ml';
  if (t.includes('500')) return '500g';
  if (t.includes('1 كيلو') || t.includes('1kg') || t.includes('كيلو') || t.includes('كجم')) return '1kg';
  if (t.includes('عبوة')) return 'عبوة';

  return '';
}

// =====================================================
// AI Output
