let parsedAI = {};
let cleanOutput = (ai.output || '{}').trim();

cleanOutput = cleanOutput
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/, '')
  .replace(/```$/, '')
  .trim();

try {
