} catch {
  parsedAI = {
    route: 'send_text',
    message: ai.output || '',
    product_id: '',
    media_url: ''
  };
}

let route = parsedAI.route || 'send_text';
let botMessage = parsedAI.message || ai.output || '';
const product_id = parsedAI.product_id || '';
const media_url = parsedAI.media_url || '';

// =====================================================
// Current Message
// =====================================================

const originalText = current.text || '';
const rawText = normalizeArabicNumerals(originalText);
const text = normalizeText(rawText);

// =====================================================
// Parse Store Order
// =====================================================

function parseStoreOrder(rawText) {
  if (!rawText.includes('NEW_BUASKOOR_ORDER')) return null;

  const lines = rawText.split('\n').map(l => l.trim()).filter(Boolean);

  const getValue = label => {
    const line = lines.find(l => l.toLowerCase().startsWith(label.toLowerCase()));
    return line ? line.replace(new RegExp(`^${label}`, 'i'), '').trim() : '';
  };

  const customer_name = getValue('Customer Name:');
  const address = getValue('Address:');
  const phoneText = getValue('Phone:');
  const notes = getValue('Notes:');

  const cart = [];

  for (const line of lines) {
    if (!line.startsWith('-')) continue;

    const qtyMatch = line.match(/Qty:\s*(\d+)/i);
    const priceMatch = line.match(/Unit Price:\s*(\d+)/i);

    const quantity = qtyMatch ? qtyMatch[1] : '1';
    const unitPrice = priceMatch ? Number(priceMatch[1]) : 0;

    const cleanLine = line.replace(/^-/, '').trim();
    const parts = cleanLine.split('|').map(p => p.trim());

    const productName = parts[0] || '';
    const weightText = parts[1] || '';

    const rule = mapProductFromName(productName);
    if (!rule) continue;

    const weight = normalizeWeight(weightText, rule.id);
    const price = unitPrice || getPrice(rule.id, weight);

    cart.push({
      id: rule.id,
      product: rule.product,
      category: rule.category,
      weight,
      quantity,
      price
    });
  }

  return {
    customer_name,
    address,
    phoneText,
    notes,
    cart
  };
}

const storeOrder = parseStoreOrder(rawText);

// =====================================================
// Normal Conversation Parser
// =====================================================

function splitIntoSegments(str) {
  const segments = [];
  const regex = /\s+و\s+|,|،|\n/g;

  let lastIndex = 0;
  let match;

  while ((match = regex.exec(str)) !== null) {
    segments.push({
      start: lastIndex,
      end: match.index,
      text: str.slice(lastIndex, match.index)
    });

    lastIndex = regex.lastIndex;
  }

  segments.push({
    start: lastIndex,
    end: str.length,
    text: str.slice(lastIndex)
  });

  return segments;
}

function findSegment(segments, position) {
  return segments.find(s => position >= s.start && position < s.end) || { text };
}

function detectProducts(text) {
  const allMatches = [];

  for (const rule of productRules) {
    for (const keyword of rule.keywords) {
      const kw = normalizeText(keyword);
      let from = 0;
      let idx;

      while ((idx = text.indexOf(kw, from)) !== -1) {
        allMatches.push({
          ...rule,
          keyword: kw,
          start: idx,
          end: idx + kw.length
        });
        from = idx + kw.length;
      }
    }
  }

  allMatches.sort((a, b) => {
    const lenDiff = (b.end - b.start) - (a.end - a.start);
    if (lenDiff !== 0) return lenDiff;
    return a.start - b.start;
  });

  const selected = [];
  const occupied = [];

  for (const m of allMatches) {
    const overlaps = occupied.some(([s, e]) => m.start < e && m.end > s);

    if (!overlaps) {
      selected.push(m);
      occupied.push([m.start, m.end]);
    }
  }

  return selected.sort((a, b) => a.start - b.start);
}

function detectCoffeeWeight(segmentText) {
  const t = normalizeText(segmentText);

  if (/(^|[^0-9])250([^0-9]|$)/.test(t) || t.includes('ربع كيلو') || t.includes('صغير')) {
    return '250g';
  }

  if (/(^|[^0-9])500([^0-9]|$)/.test(t) || t.includes('نص كيلو') || t.includes('نصف كيلو') || t.includes('وسط')) {
    return '500g';
  }

  if (t.includes('كيلو') || t.includes('كجم') || t.includes('كبير')) {
    return '1kg';
  }

  return '';
}

function detectQuantity(segmentText) {
  const t = normalizeText(segmentText);

  const qtyPatterns = [
    /qty:\s*(\d+)/i,
    /الكمية\s*[:=]?\s*(\d+)/i,
    /عدد\s*[:=]?\s*(\d+)/i
  ];

  for (const p of qtyPatterns) {
    const m = segmentText.match(p);
    if (m?.[1]) return m[1];
  }

  const wordNumbers = {
    'حبتين': '2',
    'قطعتين': '2',
    'علبتين': '2',
    'كيسين': '2',
    'عبوتين': '2',
    'اثنين': '2',
    'ثنين': '2',
    'اثنان': '2',
    'ثلاثة': '3',
    'ثلاث': '3',
    'اربعة': '4',
    'اربع': '4',
    'خمسة': '5',
    'خمس': '5',
    'ستة': '6',
    'ست': '6',
    'سبعة': '7',
    'سبع': '7',
    'ثمانية': '8',
    'ثمان': '8',
    'تسعة': '9',
    'تسع': '9',
    'عشرة': '10',
    'عشر': '10',
    'واحد': '1',
    'وحدة': '1',
    'حبة': '1'
  };

  for (const [word, num] of Object.entries(wordNumbers)) {
    if (t.includes(word)) return num;
  }

  const allNumbers = [...t.matchAll(/\d+/g)].map(m => m[0]);

  for (const num of allNumbers) {
    const isWeightNumber =
      ['250', '500', '1000'].includes(num) ||
      (num === '1' && (t.includes('كيلو') || t.includes('كجم') || t.includes('kg')));

    if (isWeightNumber) continue;

    return num;
  }

  return '1';
}

function detectPayment() {
  return {
    method: 'الدفع عند الاستلام',
    explicit: true
  };
}

function detectArea(text) {
  const areas = [
    'العين', 'ابوظبي', 'أبوظبي', 'دبي', 'الشارقة', 'عجمان',
    'الفجيرة', 'راس الخيمة', 'رأس الخيمة', 'ام القيوين', 'أم القيوين',
    'الظفرة', 'المنطقة الغربية', 'زاخر', 'الهيلي', 'اليحر',
    'الجاهلي', 'المقام', 'الطوية', 'الخبيصي', 'القوع', 'الوقن',
    'المرفأ', 'السلع', 'مدينة زايد', 'ليوا', 'دلما'
  ];

  const found = areas.find(a => text.includes(normalizeText(a)));
  return found || session.area || '';
}

function detectName(rawText) {
  const patterns = [
    /اسمي\s+([^\n،,.]+)/i,
    /الاسم\s+([^\n،,.]+)/i,
    /انا\s+([^\n،,.]+)/i,
    /أنا\s+([^\n،,.]+)/i
  ];

  for (const p of patterns) {
    const m = rawText.match(p);
    if (m?.[1]) return m[1].trim();
  }

  return session.customer_name || '';
}

function detectAddress(rawText) {
  const cleanedText = rawText
    .split('\n')
    .map(l => l.trim())
    .filter(Boolean)
    .filter(line =>
      !/^اسمي\s+/i.test(line) &&
      !/^الاسم\s+/i.test(line) &&
      !/^انا\s+/i.test(line) &&
      !/^أنا\s+/i.test(line)
    )
    .join(' ')
    .trim();

  const lower = normalizeText(cleanedText);

  const keywords = [
    'العنوان', 'موقعي', 'الموقع', 'اللوكيشن', 'location',
    'شارع', 'بناية', 'فيلا', 'بيت', 'زاخر', 'الهيلي',
    'اليحر', 'الجاهلي', 'المقام', 'الطوية', 'الخبيصي',
    'العين', 'ابوظبي', 'دبي', 'الشارقة', 'عجمان',
    'الفجيرة', 'راس الخيمة', 'ام القيوين', 'القوع',
    'الوقن', 'المنطقة الغربية', 'المرفأ', 'الظفرة',
    'السلع', 'مدينة زايد', 'ليوا', 'دلما'
  ];

  if (keywords.some(k => lower.includes(normalizeText(k)))) {
    return cleanedText;
  }

  return session.address || '';
}

function getShippingCost(address, area) {
  const haystack = normalizeText(`${address || ''} ${area || ''}`);

  const westernAreas = [
    'القوع',
    'الوقن',
    'المنطقة الغربية',
    'المرفأ',
    'الظفرة',
    'السلع',
    'مدينة زايد',
    'ليوا',
    'دلما'
  ].map(normalizeText);

  return westernAreas.some(a => haystack.includes(a)) ? 30 : 18;
}

// =====================================================
// Build Cart
// =====================================================

let cart = storeOrder ? storeOrder.cart : parseCart(session.cart);

const orderWords = [
  'عطني', 'اعطني', 'ابي', 'ابغى', 'اريد', 'اطلب',
  'طلب', 'جهز', 'خذ', 'واحد', 'وحدة', 'حبة',
  'حبتين', 'اثنين', 'ثنين', 'ثلاثة', 'ثلاث',
  'اربعة', 'خمسة', 'كيلو', 'نص كيلو', 'نصف كيلو'
];

const removalWords = [
  'شيل', 'احذف', 'حذف', 'الغاء', 'إلغاء',
  'بدون', 'ازل', 'أزل', 'كنسل'
];

const isOrderIntent =
  Boolean(storeOrder) ||
  orderWords.some(w => text.includes(normalizeText(w))) ||
  session.state === 'ordering';

const isRemovalIntent = removalWords.some(w => text.includes(normalizeText(w)));

let currentProduct = session.selected_product || '';
let currentWeight = session.selected_weight || '';
let currentQuantity = session.quantity || '';
let selected_category = session.selected_category || '';

if (!storeOrder) {
  const detectedProducts = detectProducts(text);
  const segments = splitIntoSegments(text);

  for (const item of detectedProducts) {
    const segment = findSegment(segments, item.start);
    const segmentText = segment.text || '';
    const segmentNorm = normalizeText(segmentText);

    const segmentHasRemoval = removalWords.some(w => segmentNorm.includes(normalizeText(w)));

    if (segmentHasRemoval || isRemovalIntent) {
      cart = removeFromCart(cart, item.id);

      if (currentProduct === item.product) {
        currentProduct = '';
        currentWeight = '';
        currentQuantity = '';
        selected_category = '';
      }

      continue;
    }

    if (!isOrderIntent) continue;

    let weight = item.fixedWeight || '';

    if (item.category === 'coffee') {
      weight = detectCoffeeWeight(segmentText);
    }

    const quantity = detectQuantity(segmentText);

    if (weight) {
      const price = getPrice(item.id, weight);

      cart = addOrUpdateCart(cart, {
        id: item.id,
        product: item.product,
        category: item.category,
        weight,
        quantity,
        price
      });

      if (currentProduct === item.product) {
        currentProduct = '';
        currentWeight = '';
        currentQuantity = '';
        selected_category = '';
      }
    } else if (!currentProduct) {
      currentProduct = item.product;
      currentWeight = '';
      currentQuantity = quantity;
      selected_category = item.category;
    }
  }
} else {
  currentProduct = '';
  currentWeight = '';
  currentQuantity = '';
  selected_category = '';
}

// =====================================================
// Customer Data
// =====================================================

const customer_name = storeOrder?.customer_name || detectName(rawText);
const area = detectArea(text);
const address = storeOrder?.address || detectAddress(rawText);

const paymentInfo = detectPayment();
const payment_method = paymentInfo.method;

const items_total = cart.reduce((sum, item) => {
  return sum + Number(item.price || 0) * Number(item.quantity || 1);
}, 0);

const shipping_cost = cart.length ? getShippingCost(address, area) : 0;
const grand_total = items_total + shipping_cost;

// =====================================================
// State
// =====================================================

let state = cart.length ? 'ordering' : (session.state || 'browsing');

if (cart.length && customer_name && address && !currentProduct) {
  state = 'ready_to_confirm';
}

function isConfirmation(rawText) {
  const t = normalizeText(rawText);

  if (!t) return false;
  if (['👍', '👌', '✅'].some(e => rawText.includes(e))) return true;
  if (t.length > 15) return false;

  const confirmWords = [
    'تم', 'تمام', 'موافق', 'اوكي', 'اوكيه',
    'اكيد', 'ايوا', 'ايوه', 'نعم', 'ok', 'okay'
  ];

  return confirmWords.some(w => t === normalizeText(w) || t.includes(normalizeText(w)));
}

if (session.state === 'ready_to_confirm' && isConfirmation(rawText)) {
  state = 'confirmed';

  botMessage = `شكراً جزيلاً 🤎

تم استلام طلبكم بنجاح وهو الآن قيد التجهيز.

بالهنا والعافية عليكم 🌿

وتشرفنا بخدمتكم ونتطلع لخدمتكم مرة أخرى.`;

  route = 'send_text';
}

// =====================================================
// Summary
// =====================================================

const cartSummary = cart.map((item, i) => {
  const lineTotal = Number(item.price || 0) * Number(item.quantity || 1);
  return `${i + 1}. ${item.product} - ${item.weight} - الكمية: ${item.quantity} - ${lineTotal} درهم`;
}).join('\n');

const order_summary = cart.length
  ? `
الطلب:
${cartSummary}

المجموع: ${items_total} درهم
التوصيل: ${shipping_cost} درهم
الإجمالي: ${grand_total} درهم

الاسم: ${customer_name || ''}
المنطقة: ${area || ''}
العنوان: ${address || ''}
الدفع: ${payment_method}
`.trim()
  : session.order_summary || '';

// =====================================================
// Final Bot Message
// =====================================================

if (cart.length && (isOrderIntent || isRemovalIntent) && state !== 'confirmed') {
  let finalMessage = `تم استلام طلبك من المنيو 🌿

الطلب الحالي:
${cartSummary}

المجموع: ${items_total} درهم
التوصيل: ${shipping_cost} درهم
الإجمالي: ${grand_total} درهم`;

  if (currentProduct && !currentWeight) {
    finalMessage += `

باقي نحدد وزن:
${currentProduct}

الأحجام المتوفرة:
250 جم
500 جم
1 كجم`;
  } else if (!customer_name || !address) {
    finalMessage += `

لإكمال الطلب أرسل:
الاسم:
العنوان:`;
  } else {
    finalMessage += `

الاسم: ${customer_name}
العنوان: ${address}
طريقة الدفع: ${payment_method}

إذا كل شي صحيح اكتب: تم
وسنبدأ مباشرة بتجهيز الطلب 🌿`;

    state = 'ready_to_confirm';
  }

  botMessage = finalMessage;
  route = 'send_text';
}

// =====================================================
// History
// =====================================================

const newTurn = `العميل: ${originalText}\nالمساعد: ${botMessage}`;
const historyTurns = (session.history || '').split('\n---\n').filter(Boolean);
historyTurns.push(newTurn);
const history = historyTurns.slice(-6).join('\n---\n');

// =====================================================
// Output
// =====================================================

return [{
  json: {
    ...session,

    phone: current.phone,
    state,

    cart: JSON.stringify(cart),

    selected_category,
    selected_product: currentProduct,
    selected_weight: currentWeight,
    quantity: currentQuantity,

    customer_name,
    area,
    address,
    payment_method,

    order_summary,
    items_total,
    shipping_cost,
    grand_total,

    route,
    product_id,
    media_url,

    last_user_message: originalText,
    last_bot_message: botMessage,
    output: botMessage,

    history
  }
}];

